class StockSpanner:

    def __init__(self):
        self.stack = []

    def next(self, price: int) -> int:
        while self.stack and self.stack[-1][0] <= price:
            self.stack.pop()
        if not self.stack:
            self.stack.append((price, 1))
        else:
            self.stack.append((price, self.stack[-1][1] + 1))
        return self.stack[-1][1]
```
